1	<script>
2		// Turn the probe until the meter agrees.
3		// Primary control: probeAngle, degrees, 0..360, step 5.
4		// Auxiliary control: lengthC1, relative length of candidate c1, 0.5..2, step 0.1.
5		let probeAngle = $state(40);
6		let lengthC1 = $state(1);
7	
8		let svgEl = $state(null);
9	
10		// Square canvas, centered, sized with margin for the worst case (c1
11		// stretched to 2x plus its label) at ANY angle, not just the driven
12		// states, so nothing clips or crowds regardless of where the probe or
13		// c1's length land.
14		const VIEW = 400;
15		const CENTER = 200;
16		const R = 70;
17		const MAX_SCORE = 2;
18		const HEAD_LEN_RATIO = 0.2;
19		const HEAD_WIDTH_RATIO = 0.11;
20		const LABEL_RADIAL_OFFSET = 30;
21		const PROBE_LABEL_TANGENT = 26;
22	
23		const baseCandidates = [
24			{ name: 'c1', angle: 20 },
25			{ name: 'c2', angle: 70 },
26			{ name: 'c3', angle: 110 },
27			{ name: 'c4', angle: 160 }
28		];
29	
30		function toRad(deg) {
31			return (deg * Math.PI) / 180;
32		}
33	
34		function clamp(v, min, max) {
35			return Math.min(max, Math.max(min, v));
36		}
37	
38		// Shared geometry for every arrow (probe and candidates alike) so the
39		// arrowhead-to-shaft proportion is identical everywhere: nothing is ever
40		// bloated relative to its own length.
41		function arrow(angleDeg, length) {
42			const rad = toRad(angleDeg);
43			const dirX = Math.cos(rad);
44			const dirY = -Math.sin(rad);
45			const shaft = R * length;
46			const tipX = CENTER + dirX * shaft;
47			const tipY = CENTER + dirY * shaft;
48			const headLen = shaft * HEAD_LEN_RATIO;
49			const halfWidth = shaft * HEAD_WIDTH_RATIO;
50			const backX = tipX - dirX * headLen;
51			const backY = tipY - dirY * headLen;
52			const perpX = -dirY;
53			const perpY = dirX;
54			const leftX = backX + perpX * halfWidth;
55			const leftY = backY + perpY * halfWidth;
56			const rightX = backX - perpX * halfWidth;
57			const rightY = backY - perpY * halfWidth;
58			return {
59				dirX,
60				dirY,
61				perpX,
62				perpY,
63				shaft,
64				tipX,
65				tipY,
66				backX,
67				backY,
68				poly: `${tipX},${tipY} ${leftX},${leftY} ${rightX},${rightY}`
69			};
70		}
71	
72		let candidates = $derived(
73			baseCandidates.map((c) => {
74				const length = c.name === 'c1' ? lengthC1 : 1;
75				const geo = arrow(c.angle, length);
76				const labelDist = geo.shaft + LABEL_RADIAL_OFFSET;
77				const labelX = CENTER + geo.dirX * labelDist;
78				const labelY = CENTER + geo.dirY * labelDist;
79				const diff = toRad(probeAngle - c.angle);
80				const score = Math.cos(diff) * length;
81				return { ...c, length, ...geo, labelX, labelY, score };
82			})
83		);
84	
85		let probeGeo = $derived.by(() => {
86			const geo = arrow(probeAngle, 1);
87			const labelDist = geo.shaft + LABEL_RADIAL_OFFSET;
88			// Radial reach plus a fixed tangential kick: even when the probe
89			// sits exactly on a candidate's line, the two label centers stay a
90			// fixed distance apart, independent of angle.
91			const labelX = CENTER + geo.dirX * labelDist + geo.perpX * PROBE_LABEL_TANGENT;
92			const labelY = CENTER + geo.dirY * labelDist + geo.perpY * PROBE_LABEL_TANGENT;
93			return { ...geo, labelX, labelY };
94		});
95	
96		let probeHandlePos = $derived({
97			x: (probeGeo.tipX / VIEW) * 100,
98			y: (probeGeo.tipY / VIEW) * 100
99		});
100	
101		let c1HandlePos = $derived.by(() => {
102			const c1 = candidates.find((c) => c.name === 'c1');
103			return { x: (c1.tipX / VIEW) * 100, y: (c1.tipY / VIEW) * 100 };
104		});
105	
106		function roundScore(s) {
107			let v = Math.round(s * 10) / 10;
108			if (Object.is(v, -0)) v = 0;
109			return v;
110		}
111	
112		// A leader is crowned only when its rounded score strictly beats every
113		// other rounded score. A tie for the top value suppresses the boost
114		// everywhere, so no bar is ever falsely bolded as the leader.
115		let leaderName = $derived.by(() => {
116			const rounded = candidates.map((c) => roundScore(c.score));
117			const max = Math.max(...rounded);
118			const tiedCount = rounded.filter((r) => r === max).length;
119			if (tiedCount > 1) return null;
120			return candidates[rounded.indexOf(max)].name;
121		});
122	
123		function screenToUser(e) {
124			const rect = svgEl.getBoundingClientRect();
125			const scaleX = VIEW / rect.width;
126			const scaleY = VIEW / rect.height;
127			return {
128				x: (e.clientX - rect.left) * scaleX,
129				y: (e.clientY - rect.top) * scaleY
130			};
131		}
132	
133		function angleFromPointer(e) {
134			const p = screenToUser(e);
135			const dx = p.x - CENTER;
136			const dy = p.y - CENTER;
137			let deg = (Math.atan2(-dy, dx) * 180) / Math.PI;
138			if (deg < 0) deg += 360;
139			return clamp(Math.round(deg), 0, 360);
140		}
141	
142		function lengthFromPointer(e) {
143			const p = screenToUser(e);
144			const dx = p.x - CENTER;
145			const dy = p.y - CENTER;
146			const c1Rad = toRad(20);
147			const dirX = Math.cos(c1Rad);
148			const dirY = -Math.sin(c1Rad);
149			const proj = dx * dirX + dy * dirY;
150			const len = proj / R;
151			return clamp(Math.round(len * 10) / 10, 0.5, 2);
152		}
153	
154		function onProbePointerDown(e) {
155			e.preventDefault();
156			e.currentTarget.setPointerCapture(e.pointerId);
157			probeAngle = angleFromPointer(e);
158		}
159	
160		function onProbePointerMove(e) {
161			if (e.buttons === 0) return;
162			probeAngle = angleFromPointer(e);
163		}
164	
165		function onProbePointerUp(e) {
166			try {
167				e.currentTarget.releasePointerCapture(e.pointerId);
168			} catch (err) {
169				/* no-op: capture may already be released */
170			}
171		}
172	
173		function onProbeKeydown(e) {
174			let handled = true;
175			if (e.key === 'ArrowRight' || e.key === 'ArrowUp') probeAngle = clamp(probeAngle + 5, 0, 360);
176			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') probeAngle = clamp(probeAngle - 5, 0, 360);
177			else if (e.key === 'Home') probeAngle = 0;
178			else if (e.key === 'End') probeAngle = 360;
179			else handled = false;
180			if (handled) e.preventDefault();
181		}
182	
183		function onLengthPointerDown(e) {
184			e.preventDefault();
185			e.currentTarget.setPointerCapture(e.pointerId);
186			lengthC1 = lengthFromPointer(e);
187		}
188	
189		function onLengthPointerMove(e) {
190			if (e.buttons === 0) return;
191			lengthC1 = lengthFromPointer(e);
192		}
193	
194		function onLengthPointerUp(e) {
195			try {
196				e.currentTarget.releasePointerCapture(e.pointerId);
197			} catch (err) {
198				/* no-op: capture may already be released */
199			}
200		}
201	
202		function onLengthKeydown(e) {
203			let handled = true;
204			if (e.key === 'ArrowRight' || e.key === 'ArrowUp')
205				lengthC1 = clamp(Math.round((lengthC1 + 0.1) * 10) / 10, 0.5, 2);
206			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown')
207				lengthC1 = clamp(Math.round((lengthC1 - 0.1) * 10) / 10, 0.5, 2);
208			else if (e.key === 'Home') lengthC1 = 0.5;
209			else if (e.key === 'End') lengthC1 = 2;
210			else handled = false;
211			if (handled) e.preventDefault();
212		}
213	</script>
214	
215	<div class="wrap" data-interactive="dot-alignment">
216		<p class="instruction">Turn the probe until the meter agrees. Stretch c1's handle to see length cheat direction.</p>
217	
218		<div class="stage">
219			<svg
220				bind:this={svgEl}
221				viewBox="0 0 {VIEW} {VIEW}"
222				class="diagram"
223				aria-label="An amber probe arrow rotates among four periwinkle candidate arrows named c1 through c4"
224			>
225				<circle cx={CENTER} cy={CENTER} r="3" fill="var(--color-text)" opacity="0.25" aria-hidden="true" />
226	
227				{#each candidates as c (c.name)}
228					<line
229						x1={CENTER}
230						y1={CENTER}
231						x2={c.backX}
232						y2={c.backY}
233						stroke="var(--data-observed)"
234						stroke-width="2"
235						stroke-linecap="round"
236						opacity="0.85"
237					/>
238					<polygon points={c.poly} fill="var(--data-observed)" opacity="0.85" />
239					<text
240						x={c.labelX}
241						y={c.labelY}
242						class="arrow-label"
243						text-anchor="middle"
244						dominant-baseline="middle"
245						aria-hidden="true">{c.name}</text
246					>
247				{/each}
248	
249				<line
250					x1={CENTER}
251					y1={CENTER}
252					x2={probeGeo.backX}
253					y2={probeGeo.backY}
254					stroke="var(--data-heat)"
255					stroke-width="3"
256					stroke-linecap="round"
257				/>
258				<polygon points={probeGeo.poly} fill="var(--data-heat)" />
259				<text
260					x={probeGeo.labelX}
261					y={probeGeo.labelY}
262					class="arrow-label probe-label"
263					text-anchor="middle"
264					dominant-baseline="middle"
265					aria-hidden="true">probe</text
266				>
267			</svg>
268	
269			<div
270				class="handle probe-handle"
271				style="left: {probeHandlePos.x}%; top: {probeHandlePos.y}%;"
272				role="slider"
273				tabindex="0"
274				aria-label="probe angle in degrees"
275				aria-valuemin="0"
276				aria-valuemax="360"
277				aria-valuenow={Math.round(probeAngle)}
278				onpointerdown={onProbePointerDown}
279				onpointermove={onProbePointerMove}
280				onpointerup={onProbePointerUp}
281				onkeydown={onProbeKeydown}
282			></div>
283	
284			<div
285				class="handle length-handle"
286				style="left: {c1HandlePos.x}%; top: {c1HandlePos.y}%;"
287				data-control="length-c1"
288				role="spinbutton"
289				tabindex="0"
290				aria-label="c1 length"
291				aria-valuemin="0.5"
292				aria-valuemax="2"
293				aria-valuenow={lengthC1.toFixed(1)}
294				onpointerdown={onLengthPointerDown}
295				onpointermove={onLengthPointerMove}
296				onpointerup={onLengthPointerUp}
297				onkeydown={onLengthKeydown}
298			></div>
299		</div>
300	
301		<div class="scores">
302			{#each candidates as c (c.name)}
303				{@const displayScore = roundScore(c.score).toFixed(1)}
304				{@const isLeading = c.name === leaderName}
305				<div class="score-col">
306					<div class="bar-track">
307						<div class="bar-zero" aria-hidden="true"></div>
308						<div
309							class="bar-fill"
310							class:leading={isLeading}
311							style="height: {Math.min(Math.abs(c.score), MAX_SCORE) / MAX_SCORE * 44}px; {c.score >= 0
312								? 'bottom: 50%;'
313								: 'top: 50%;'}"
314						></div>
315					</div>
316					<span class="readout" class:leading={isLeading} aria-label="{c.name} score {displayScore}"
317						>{displayScore}</span
318					>
319					<span class="cand-label" aria-hidden="true">{c.name}</span>
320				</div>
321			{/each}
322		</div>
323	</div>
324	
325	<style>
326		.wrap {
327			display: flex;
328			flex-direction: column;
329			align-items: center;
330			gap: 1rem;
331			width: 100%;
332			max-width: 520px;
333			margin: 0 auto;
334			padding: 1.25rem 1rem;
