input.old_string:
.handle {
	position: absolute;
	width: 48px;
	height: 48px;
	transform: translate(-50%, -50%);
	display: flex;
	align-items: center;
	justify-content: center;
	touch-action: none;
	cursor: grab;
	background: transparent;
	border: none;
	padding: 0;
}

.probe-handle::before {
	content: '';
	width: 14px;
	height: 14px;
	border-radius: 50%;
	background: var(--data-heat);
	box-shadow: 0 0 0 3px var(--color-bg);
}

.length-handle::before {
	content: '';
	width: 12px;
	height: 12px;
	border-radius: 50%;
	background: var(--data-observed);
	box-shadow: 0 0 0 3px var(--color-bg);
}

.handle:focus-visible::before {
	box-shadow: 0 0 0 3px var(--color-bg), 0 0 0 5px currentColor;
}

.probe-handle:focus-visible::before {
	color: var(--data-heat);
}

.length-handle:focus-visible::before {
	color: var(--data-observed);
}

