	position: absolute;
	inset: 0;
	touch-action: none;
	cursor: grab;
	background: transparent;
	border: none;
	padding: 0;
	border-radius: 50%;
}

.slider-surface:focus-visible {
	outline: 2px solid var(--data-heat);
	outline-offset: 3px;
}

